// generar_264_fix_tipo_trucos.js
// CHIQUI Entre Señales — Fix build del 262: tipo local sin 'trucos'
//
// Error de compilación:
//   Type error: 'trucos' does not exist in type
//   '{ duracion: number | null; nota: string; }'
//
// Causa: el 262 actualizó el tipo del estado enriqDatos para incluir
// los trucos de entrenamiento, pero dentro de cargarEnriquecimientos
// quedó una variable local (datos) con la anotación de tipo antigua.
// Babel no detecta errores de tipos (solo sintaxis), por eso pasó la
// validación local y falló recién en el type-check de Vercel — misma
// clase de error que el import del 254.
//
// Fix: la anotación local ahora incluye trucos?: string[].
//
// NOTA: este script escribe app/registro-diario/page.tsx completo e
// incluye TODO lo anterior: 260 (enriquecimiento y cuidados), 261
// (hitos), 262 (trucos) y 263 (hitos con UI optimista y errores
// visibles). Córrelo EN VEZ del 263 — ya no necesitas correr ese.
//
// Uso:
//   node generar_264_fix_tipo_trucos.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'app/registro-diario/page.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 1 archivo escrito (incluye 260-264). git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
